"const fs = require('fs');
const readline = require('readline');

const logFilePath = 'C:\\Users\\upris\\.gemini\\antigravity\\brain\\2147ffbd-752b-4024-a122-61e0cb883110\\.system_generated\\logs\\transcript.jsonl';

async function findInstructions() {
  const fileStream = fs.createReadStream(logFilePath);
  const rl = readline.createInterface({
    input: fileStream,
    crlfDelay: Infinity
  });

  let index = 0;
  for await (const line of rl) {
    if (line.includes('d12165a7-6c3b-4efc-a754-e9fdb60833fe')) {
      const obj = JSON.parse(line);
      console.log(`Match ${index}: type = ${obj.type}, source = ${obj.source}`);
      fs.writeFileSync(`C:\\Users\\upris\\content-osv2\\Vectra OS\\apps\\web\\nylas_ui_raw_step_${index}.json`, JSON.stringify(obj, null, 2));
      index++;
    }
  }
  console.log(`Found ${index} matches.`);
}

findInstructions();
"
